class DataController extends GetxController {
  var data = ''.obs;
  var error = ''.obs;
  var retryCount = 0.obs;
  var isRetrying = false.obs;

  @override
  void onInit() {
    super.onInit();
    // Listen to error and automatically retry (max 3 times)
    ever(error, (err) async {
      if (err.isNotEmpty && retryCount.value < 3 && !isRetrying.value) {
        isRetrying.value = true;
        await Future.delayed(Duration(seconds: 2));
        retryCount.value++;
        await fetchData();
        isRetrying.value = false;
      }
    });
  }

  Future<void> fetchData() async {
    error.value = '';
    try {
      final result = await api.getData();
      data.value = result;
      retryCount.value = 0; // reset on success
    } catch (e) {
      error.value = e.toString();
    }
  }
}

class DataController extends GetxController {
  var data = ''.obs;
  var error = ''.obs;
  var retryDelay = 0.obs;
  Timer? _timer;

  Future<void> fetchData() async {
    error.value = '';
    try {
      final result = await api.getData();
      data.value = result;
    } catch (e) {
      error.value = e.toString();
      _startRetryCountdown();
    }
  }

  void _startRetryCountdown() {
    retryDelay.value = 3;
    _timer?.cancel();
    _timer = Timer.periodic(Duration(seconds: 1), (timer) {
      if (retryDelay.value <= 1) {
        timer.cancel();
        fetchData();
      } else {
        retryDelay.value--;
      }
    });
  }

  @override
  void onClose() {
    _timer?.cancel();
    super.onClose();
  }
}

